// KOTA Autonomous Control Logic
// Reads full sensor state from Python physics engine
// Issues corrective device commands for all 5 controlled devices

const env = msg.payload;
const commands = [];

// ---- KURAL 1: NEM YÖNETİMİ ----
// Kabin nemi %62 üzerine çıkarsa Dehumidifier'ı aç
// Atmosferik su hasadı: havayı kurutur ve suyu tanka geri gönderir
if (env.chamber_humidity > 62.0) {
    commands.push({ payload: { device: 'dehumidifier', action: true } });
} else if (env.chamber_humidity < 50.0) {
    commands.push({ payload: { device: 'dehumidifier', action: false } });
}

// ---- KURAL 2: SICAKLIK YÖNETİMİ ----
// Sıcaklık ISS eşiğini geçerse havalandırma fanını aç
// Fan: ISS ortam sıcaklığıyla karışım sağlar
if (env.chamber_temperature > 24.5) {
    commands.push({ payload: { device: 'ventilation_fan', action: true } });
} else if (env.chamber_temperature < 23.5) {
    commands.push({ payload: { device: 'ventilation_fan', action: false } });
}

// ---- KURAL 3: pH KONTROLܒ ----
// pH 6.5 üzerine çıkarsa asit pompasını aç (bitkiler pH 5.5-6.5 arasını tercih eder)
// Python motoru da pH'yı kontrol eder ama Node-RED ikinci güvenlik katmanıdır
if (env.ph > 6.5) {
    commands.push({ payload: { device: 'ph_doser', action: true } });
} else if (env.ph < 5.8) {
    commands.push({ payload: { device: 'ph_doser', action: false } });
}

// ---- KURAL 4: NPK BESIN KONTROLÜ ----
// Herhangi bir mineral 40 ppm altına düşerse gübre dozlayıcıyı aç
// Bu Node-RED katmanı Python motorundaki auto-restock ile paralel çalışır
const minNPK = Math.min(env.mineral_n, env.mineral_p, env.mineral_k);
if (minNPK < 40.0) {
    commands.push({ payload: { device: 'npk_doser', action: true } });
} else if (minNPK > 90.0) {
    commands.push({ payload: { device: 'npk_doser', action: false } });
}

// ---- KURAL 5: ACİL SU YÖNETİMİ ----
// Su tankı 4L altına düşerse dehumidifier'ı zorla aç
// Python motoru da bunu yapar; bu çift güvenlik katmanıdır
if (env.water_tank_liters < 4.0) {
    commands.push({ payload: { device: 'dehumidifier', action: true } });
    node.warn('ACİL: Su tankı kritik seviyede! Dehumidifier zorla açıldı.');
}

// Her komutu ayrı mesaj olarak döndür (post_command her birini ayrı POST atar)
if (commands.length === 0) {
    return null; // nothing to do this tick
}
return [commands];
